"import urllib.request
import zipfile
import io

url = "https://github.com/divakarpandey07/AI-Palmistry-pro/actions/runs/30085299979/logs"
req = urllib.request.Request(url, headers={
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
})

try:
    with urllib.request.urlopen(req) as resp:
        content = resp.read()
        print(f"Downloaded log zip size: {len(content)} bytes")
        with zipfile.ZipFile(io.BytesIO(content)) as z:
            print("Files in log zip:", z.namelist())
            for name in z.namelist():
                if "Build Debug APK" in name or "build" in name.lower() or "1_" in name:
                    print(f"--- Log File: {name} ---")
                    log_data = z.read(name).decode("utf-8", errors="ignore")
                    lines = log_data.splitlines()
                    for l in lines:
                        if any(k in l.lower() for k in ["e:", "error:", "failed", "exception", "failure"]):
                            print("  ", l[:140])
except Exception as e:
    print(f"Error fetching run log zip: {e}")
